// Pass through the aggregated review decision from Collect All Reviews.
// Decision was already made deterministically — no AI call needed.
const aggregate = $('Collect All Reviews').first().json;
return [{ json: aggregate }];

// ============================================================
// Generate blog metadata via AI.
// ============================================================

const chapter = $('Call Writer Service').first().json.data;
const project = $('Load Active Project').first().json;

return [{
  json: {
    chapter: chapter,
    project: project,
    blog_config: {
      provider: project.publish_platform || 'wordpress',
      auto_publish: $('Build Writing Brief').first().json.auto_publish,
      final_score: $('Collect All Reviews').first().json.final_score
    }
  }
}];

// ============================================================
// Parse blog metadata and publish to WordPress or REST API.
// ============================================================

const response = $input.first().json;
let metadata;
try {
  metadata = JSON.parse(response.choices[0].message.content);
} catch (e) {
  metadata = response;
}

const buildBrief = $('Build Writing Brief').first().json;
const chapter = $('Call Writer Service').first().json.data;
const finalScore = $('Collect All Reviews').first().json.final_score;
const shouldPublish = buildBrief.auto_publish && finalScore >= buildBrief.quality_threshold;

return [{
  json: {
    title: metadata.title || chapter.title,
    slug: metadata.slug || '',
    excerpt: metadata.excerpt || '',
    tags: metadata.tags || [],
    category: metadata.category || '',
    seo_description: metadata.seo_description || '',
    content_markdown: chapter.body_markdown,
    wordpress_status: shouldPublish ? 'publish' : 'draft',
    project_id: buildBrief.project_id,
    chapter_id: $('Save Chapter').first().json.id,
    should_publish: shouldPublish
  }
}];

// ============================================================
// Check if blog post already exists for this chapter.
// If exists, prepare update. If not, prepare create.
// ============================================================

const meta = $input.first().json;
const existingBlogPost = $input.all().find(i => i.json.external_post_id);

return [{
  json: {
    ...meta,
    existing_post_id: existingBlogPost?.json.external_post_id || null,
    action: existingBlogPost?.json.external_post_id ? 'update' : 'create'
  }
}];

// ============================================================
// Update canon from chapter output:
// - Chapter summaries
// - Character state changes
// - Timeline events
// - Foreshadowing
// - Vector embeddings for new content
// ============================================================

const chapter = $('Call Writer Service').first().json.data;
const projectId = $('Build Writing Brief').first().json.project_id;
const chapterId = $('Save Chapter').first().json.id;

const updates = [];

// Update chapter plan status
updates.push({
  json: {
    sql: "UPDATE chapter_plans SET status = 'draft_complete', updated_at = now() WHERE id = $1",
    values: [$('Build Writing Brief').first().json.chapter_plan_id]
  }
});

// Update chapter status
updates.push({
  json: {
    sql: "UPDATE chapters SET status = 'final', publish_status = $2, updated_at = now() WHERE id = $1",
    values: [chapterId, $('Parse Blog Metadata').first().json.wordpress_status]
  }
});

// Generate chapter summary embedding for vector store
if (chapter.summary) {
  updates.push({
    json: {
      action: 'embed_and_store',
      project_id: projectId,
      source_type: 'chapter_summary',
      source_id: chapterId,
      title: `Ch${$('Select Next Chapter Plan').first().json.sequence} 摘要: ${chapter.title}`,
      content: chapter.summary
    }
  });
}

// Character state changes for next chapter context
(chapter.character_state_changes || []).forEach(csc => {
  updates.push({
    json: {
      sql: `INSERT INTO character_states (project_id, character_id, chapter_id, physical_state, emotional_state, relationship_state)
      SELECT $1, c.id, $2, $3, $4, $5
      FROM characters c
      WHERE c.project_id = $1 AND c.name = $6 AND c.is_locked = false
      ON CONFLICT DO NOTHING`,
      values: [projectId, chapterId, csc.before, csc.after, JSON.stringify({}), csc.character_name]
    }
  });
});

// Timeline events
(chapter.timeline_events || []).forEach(te => {
  updates.push({
    json: {
      sql: `INSERT INTO timeline_events (project_id, event_time_label, event_summary, involved_characters, involved_locations, consequences, source_chapter_id)
      VALUES ($1, $2, $3, $4, $5, $6, $7)`,
      values: [projectId, te.event_time_label, te.event_summary, te.involved_characters || [], te.involved_locations || [], te.consequences || [], chapterId]
    }
  });
});

// Foreshadowing
(chapter.foreshadowing_used || []).forEach(fu => {
  if (fu.usage === 'resolved') {
    // Mark as resolved but don't auto-resolve without confirmation
    updates.push({
      json: {
        sql: `UPDATE foreshadowing SET status = 'reinforced', updated_at = now() WHERE clue_text = $1 AND project_id = $2 AND is_locked = false`,
        values: [fu.clue, projectId]
      }
    });
  }
});

return updates;
